  ('dietitian-moex-01058', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於燒傷病人的液體補充原則，下列敘述何者錯誤？', '["受傷後24小時所需要的水分，75%的總量在前8小時給足，剩餘的25%量在後16小時平均給予", "水分及電解質補充量的多寡受到年齡、體重及燒傷面積的影響", "燒傷急性初期臨床上常用乳酸林格式液（lactatedRinger''ssolution）為液體補充液", "可用血鈉值、血液滲透壓和體重來監測及補充體液"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
